import React from 'react';

export default function SettingsPanel({ demoMode, setDemoMode, onClose }){
  return (
    <div className="w-64 bg-white border rounded shadow p-4">
      <div className="flex justify-between items-center mb-3">
        <div className="font-semibold">Settings</div>
        <button onClick={onClose} className="text-sm">Close</button>
      </div>

      <div className="mb-2">
        <label className="flex items-center space-x-2">
          <input type="checkbox" checked={demoMode} onChange={e => setDemoMode(e.target.checked)} />
          <span>Use Mock APIs</span>
        </label>
        <div className="text-xs text-gray-500 mt-1">Toggle between mock and live API endpoints.</div>
      </div>

    </div>
  );
}
